+            ftui::text::Span::styled(
+                "Welcome to CASS - Coding Agent Session Search".to_string(),
+                title_style,
+            ),
+        ]));
+        lines.push(ftui::text::Line::from(""));
+        lines.push(ftui::text::Line::from("  Layout:"));
+        for row in [
+            "  ┌─────────────────────────────────────────────────┐",
+            "  │ [Search Bar]         [Filter Chips]    [Status] │",
+            "  ├────────────────┬────────────────────────────────┤",
+            "  │                │                                │",
+            "  │   Results      │       Detail Preview           │",
+            "  │   (Left/↑↓)    │       (Tab to focus)           │",
+            "  │                │                                │",
+            "  ├────────────────┴────────────────────────────────┤",
+            "  │ [Help Strip]                                    │",
+            "  └─────────────────────────────────────────────────┘",
+        ] {
